   100→template <typename IRUnitT, typename... ExtraArgTs>
   101→inline AnalysisManager<IRUnitT, ExtraArgTs...>::AnalysisManager() = default;
   102→
   103→template <typename IRUnitT, typename... ExtraArgTs>
   104→inline AnalysisManager<IRUnitT, ExtraArgTs...>::AnalysisManager(
   105→    AnalysisManager &&) = default;
   106→
   107→template <typename IRUnitT, typename... ExtraArgTs>
   108→inline AnalysisManager<IRUnitT, ExtraArgTs...> &
   109→AnalysisManager<IRUnitT, ExtraArgTs...>::operator=(AnalysisManager &&) =
   110→    default;
   111→
   112→template <typename IRUnitT, typename... ExtraArgTs>
   113→inline void
   114→AnalysisManager<IRUnitT, ExtraArgTs...>::clear(IRUnitT &IR,
   115→                                               llvm::StringRef Name) {
   116→  if (auto *PI = getCachedResult<PassInstrumentationAnalysis>(IR))
   117→    PI->runAnalysesCleared(Name);
   118→
   119→  auto ResultsListI = AnalysisResultLists.find(&IR);
   120→  if (ResultsListI == AnalysisResultLists.end())
   121→    return;
   122→  // Delete the map entries that point into the results list.
   123→  for (auto &IDAndResult : ResultsListI->second)
   124→    AnalysisResults.erase({IDAndResult.first, &IR});
   125→
   126→  // And actually destroy and erase the results associated with this IR.
   127→  AnalysisResultLists.erase(ResultsListI);
   128→}
   129→
   130→template <typename IRUnitT, typename... ExtraArgTs>
   131→inline typename AnalysisManager<IRUnitT, ExtraArgTs...>::ResultConceptT &
   132→AnalysisManager<IRUnitT, ExtraArgTs...>::getResultImpl(
   133→    AnalysisKey *ID, IRUnitT &IR, ExtraArgTs... ExtraArgs) {
   134→  auto [RI, Inserted] = AnalysisResults.try_emplace(std::make_pair(ID, &IR));
   135→
   136→  // If we don't have a cached result for this function, look up the pass and
   137→  // run it to produce a result, which we then add to the cache.
   138→  if (Inserted) {
   139→    auto &P = this->lookUpPass(ID);
   140→
   141→    PassInstrumentation PI;
   142→    if (ID != PassInstrumentationAnalysis::ID()) {
   143→      PI = getResult<PassInstrumentationAnalysis>(IR, ExtraArgs...);
   144→      PI.runBeforeAnalysis(P, IR);
   145→    }
   146→
   147→    AnalysisResultListT &ResultList = AnalysisResultLists[&IR];
   148→    ResultList.emplace_back(ID, P.run(IR, *this, ExtraArgs...));
   149→
   150→    PI.runAfterAnalysis(P, IR);
   151→
   152→    // P.run may have inserted elements into AnalysisResults and invalidated
   153→    // RI.
   154→    RI = AnalysisResults.find({ID, &IR});
   155→    assert(RI != AnalysisResults.end() && "we just inserted it!");
   156→
   157→    RI->second = std::prev(ResultList.end());
   158→  }
   159→
   160→  return *RI->second->second;
   161→}
