   163→template <typename IRUnitT, typename... ExtraArgTs>
   164→inline void AnalysisManager<IRUnitT, ExtraArgTs...>::invalidate(
   165→    IRUnitT &IR, const PreservedAnalyses &PA) {
   166→  // We're done if all analyses on this IR unit are preserved.
   167→  if (PA.allAnalysesInSetPreserved<AllAnalysesOn<IRUnitT>>())
   168→    return;
   169→
   170→  // Track whether each analysis's result is invalidated in
   171→  // IsResultInvalidated.
   172→  SmallDenseMap<AnalysisKey *, bool, 8> IsResultInvalidated;
   173→  Invalidator Inv(IsResultInvalidated, AnalysisResults);
   174→  AnalysisResultListT &ResultsList = AnalysisResultLists[&IR];
   175→  for (auto &AnalysisResultPair : ResultsList) {
   176→    // This is basically the same thing as Invalidator::invalidate, but we
   177→    // can't call it here because we're operating on the type-erased result.
   178→    // Moreover if we instead called invalidate() directly, it would do an
   179→    // unnecessary look up in ResultsList.
   180→    AnalysisKey *ID = AnalysisResultPair.first;
   181→    auto &Result = *AnalysisResultPair.second;
   182→
   183→    auto IMapI = IsResultInvalidated.find(ID);
   184→    if (IMapI != IsResultInvalidated.end())
   185→      // This result was already handled via the Invalidator.
   186→      continue;
   187→
